/**
 * Borehole Database Module — Regional Drilling History & Statistics
 *
 * Provides historical borehole data for any location by:
 *   1. Forward geocoding the client's location (country, region, city, village)
 *   2. Looking up known borehole databases by country AND county/region
 *   3. Generating region-calibrated statistics (depth, yield, success)
 *      based on national drilling surveys and published data
 *   4. Providing direct links to national borehole databases
 *   5. Sub-national (county/region) statistics for Kenya, Uganda, Ethiopia, Tanzania, South Africa
 *
 * Sources: WASREB, WRA Kenya, BGS Africa Groundwater Atlas, RWSN, WPDx, UNICEF WASH
 */

// ─── Kenya County-Level Borehole Intelligence ───
// Source: Kenya WRA Borehole Completion Reports, WASREB County Water Data,
// BGS Africa Groundwater Atlas, KNBS 2019 Census Water Data, WPDx analysis
export interface CountyBoreholeStats {
  county: string;
  estimatedBoreholes: number;     // Total estimated boreholes in county
  avgDepth_m: number;
  depthRange: [number, number];
  avgYield_m3h: number;
  yieldRange: [number, number];
  successRate: number;            // 0-1
  primaryGeology: string;
  aquiferType: string;
  avgWaterTable_m: number;
  waterTableRange: [number, number];
  drillingCostPerM_USD: [number, number];
  keyRisks: string[];
  notes: string;
}

