// Lookup by approximate county from coordinates (All 47 Kenya counties)
function getKenyaCountyFromCoords(lat: number, lon: number): string | null {
  // Approximate bounding boxes for all Kenya counties
  // Ordered from smallest/most-specific to largest to handle overlapping bounds
  const countyBounds: { county: string; latRange: [number, number]; lonRange: [number, number] }[] = [
    // ─── Small/Urban counties (check first) ───
    { county: 'mombasa', latRange: [-4.15, -3.9], lonRange: [39.55, 39.8] },
    { county: 'nairobi', latRange: [-1.45, -1.15], lonRange: [36.65, 37.0] },
    // Vihiga spans ~34.55-34.85E (Luanda sub-county sits at ~34.56-34.65E) —
    // the old 34.65 west edge dropped real Vihiga sites into Kakamega's box.
    { county: 'vihiga', latRange: [-0.02, 0.15], lonRange: [34.55, 34.85] },

    // ─── Central Highlands ───
    { county: "murang'a", latRange: [-1.12, -0.58], lonRange: [36.7, 37.35] },
    { county: 'kiambu', latRange: [-1.35, -0.95], lonRange: [36.55, 37.05] },
    { county: 'nyeri', latRange: [-0.75, -0.25], lonRange: [36.65, 37.2] },
    { county: 'kirinyaga', latRange: [-0.7, -0.35], lonRange: [37.15, 37.5] },
    { county: 'embu', latRange: [-0.8, -0.3], lonRange: [37.3, 37.85] },
    { county: 'nyandarua', latRange: [-0.85, -0.2], lonRange: [36.2, 36.7] },
    { county: 'tharaka-nithi', latRange: [-0.45, 0.05], lonRange: [37.55, 38.15] },
    { county: 'meru', latRange: [-0.4, 0.35], lonRange: [37.4, 38.2] },

    // ─── Eastern ───
    { county: 'machakos', latRange: [-1.65, -1.0], lonRange: [36.95, 37.75] },
    { county: 'makueni', latRange: [-2.5, -1.6], lonRange: [37.1, 38.2] },
    { county: 'kitui', latRange: [-1.8, -0.7], lonRange: [37.7, 39.0] },

    // ─── Rift Valley ───
    { county: 'nakuru', latRange: [-1.1, -0.15], lonRange: [35.75, 36.6] },
    { county: 'kajiado', latRange: [-2.85, -1.35], lonRange: [36.0, 37.2] },
    { county: 'baringo', latRange: [-0.1, 1.2], lonRange: [35.6, 36.45] },
    { county: 'narok', latRange: [-2.2, -0.9], lonRange: [34.9, 36.2] },
    { county: 'bomet', latRange: [-1.1, -0.5], lonRange: [35.15, 35.65] },
    { county: 'kericho', latRange: [-0.65, -0.05], lonRange: [35.1, 35.7] },
    { county: 'elgeyo-marakwet', latRange: [0.3, 1.2], lonRange: [35.3, 35.8] },
    { county: 'nandi', latRange: [-0.05, 0.5], lonRange: [34.85, 35.45] },
    { county: 'uasin gishu', latRange: [0.15, 0.85], lonRange: [34.95, 35.6] },
    { county: 'laikipia', latRange: [-0.3, 0.55], lonRange: [36.15, 37.3] },
    { county: 'west pokot', latRange: [1.0, 2.1], lonRange: [34.75, 35.7] },
    { county: 'samburu', latRange: [0.5, 2.5], lonRange: [36.2, 38.0] },
    { county: 'trans-nzoia', latRange: [0.75, 1.2], lonRange: [34.7, 35.2] },

    // ─── Western ───
    { county: 'kakamega', latRange: [0.0, 0.55], lonRange: [34.5, 35.0] },
    { county: 'bungoma', latRange: [0.4, 1.0], lonRange: [34.3, 34.95] },
    { county: 'busia', latRange: [-0.15, 0.5], lonRange: [33.9, 34.45] },
    { county: 'siaya', latRange: [-0.35, 0.15], lonRange: [33.85, 34.55] },
    { county: 'kisumu', latRange: [-0.35, 0.1], lonRange: [34.55, 35.15] },
    { county: 'homa bay', latRange: [-0.85, -0.2], lonRange: [34.0, 34.8] },
    { county: 'migori', latRange: [-1.25, -0.65], lonRange: [33.85, 34.6] },
    { county: 'nyamira', latRange: [-0.85, -0.45], lonRange: [34.75, 35.15] },

    // ─── Coastal ───
    { county: 'kilifi', latRange: [-4.0, -2.5], lonRange: [39.2, 40.2] },
    { county: 'kwale', latRange: [-4.65, -3.5], lonRange: [38.8, 39.65] },
    { county: 'taita-taveta', latRange: [-3.85, -2.6], lonRange: [37.6, 39.0] },
    { county: 'lamu', latRange: [-2.55, -1.6], lonRange: [40.0, 41.6] },
    { county: 'tana river', latRange: [-2.6, -0.7], lonRange: [38.5, 40.4] },

    // ─── Arid North & Northeast (largest counties — check last) ───
    { county: 'isiolo', latRange: [0.0, 2.0], lonRange: [37.5, 39.5] },
    { county: 'garissa', latRange: [-2.0, 1.5], lonRange: [39.0, 41.5] },
    { county: 'wajir', latRange: [0.5, 3.5], lonRange: [39.0, 41.0] },
    { county: 'mandera', latRange: [2.5, 4.0], lonRange: [39.5, 41.5] },
    { county: 'marsabit', latRange: [1.5, 4.5], lonRange: [36.5, 39.5] },
    { county: 'turkana', latRange: [1.5, 5.0], lonRange: [34.0, 36.5] },
  ];
  for (const cb of countyBounds) {
    if (lat >= cb.latRange[0] && lat <= cb.latRange[1] && lon >= cb.lonRange[0] && lon <= cb.lonRange[1]) {
      return cb.county;
    }
  }
  return null;
}

export function getKenyaCountyBoreholeStats(lat: number, lon: number): CountyBoreholeStats | null {
  const county = getKenyaCountyFromCoords(lat, lon);
  if (!county) return null;
  return KENYA_COUNTY_BOREHOLE_DATA[county] ?? null;
}

/**
 * Name-based county lookup — ALWAYS preferred over the coordinate bounding-box
 * test when a geocoded admin hierarchy is available.
 *
 * AUDIT FIX (2026-07-16): a Vihiga site at lon 34.6472 fell 0.003° outside
 * Vihiga's approximate bbox and was silently assigned KAKAMEGA's drilling
 * record ("same hydrogeological unit" with the wrong county's geology). The
 * report already KNEW the county from reverse geocoding — trust that first.
 */
export function getKenyaCountyBoreholeStatsByName(...names: (string | undefined | null)[]): CountyBoreholeStats | null {
  for (const raw of names) {
    if (!raw) continue;
    const n = String(raw).toLowerCase()
      .replace(/\bcounty\b/g, '').replace(/[’]/g, "'").replace(/\s+/g, ' ').trim();
    if (!n) continue;
    if (KENYA_COUNTY_BOREHOLE_DATA[n]) return KENYA_COUNTY_BOREHOLE_DATA[n];
    // tolerate "Vihiga District", "Uasin-Gishu", hyphen/space variants
    const compact = n.replace(/[^a-z']/g, '');
    for (const key of Object.keys(KENYA_COUNTY_BOREHOLE_DATA)) {
      if (key.replace(/[^a-z']/g, '') === compact) return KENYA_COUNTY_BOREHOLE_DATA[key];
    }
  }
  return null;
}

export interface RegionalBoreholeStats {
  country: string;
  countryCode: string;
  region?: string;
  averageDepth: number;        // meters
  depthRange: [number, number]; // min-max
  averageYield: number;        // m³/hour
  yieldRange: [number, number];
  successRate: number;         // 0-1
  totalBoreholesDrilled: string;  // approximate national figure
  commonAquiferTypes: string[];
  commonGeology: string[];
  averageCost: string;         // USD range per meter
  typicalWaterTable: string;
  databaseLinks: { name: string; url: string; description: string }[];
  source: string;
  notes: string[];
}

export interface GeologicalFormation {
  name: string;
  depthRange: [number, number];
  yieldRange: [number, number];
  aquiferType: string;
  successRate: number;
  notes: string;
}

