/**
 * Common geological formations and their drilling characteristics.
 * Used to refine depth/yield estimates when we know the country/region.
 */
export const GEOLOGICAL_FORMATIONS: GeologicalFormation[] = [
  { name: 'Fractured Basement Complex', depthRange: [40, 200], yieldRange: [0.3, 8], aquiferType: 'Fractured', successRate: 0.55, notes: 'Target fracture zones. VES/resistivity essential.' },
  { name: 'Weathered Basement (Regolith)', depthRange: [10, 60], yieldRange: [0.5, 5], aquiferType: 'Unconfined/weathered zone', successRate: 0.70, notes: 'Shallow, lower yield, easier to drill' },
  { name: 'Volcanic (Basalt)', depthRange: [30, 250], yieldRange: [1, 30], aquiferType: 'Fractured volcanic', successRate: 0.65, notes: 'Highly variable — fractures and interflow zones are targets' },
  { name: 'Alluvial / Floodplain', depthRange: [10, 80], yieldRange: [2, 40], aquiferType: 'Intergranular', successRate: 0.85, notes: 'Best aquifers — high yield, easy drilling. Contamination risk near surface.' },
  { name: 'Sedimentary (Sandstone)', depthRange: [30, 300], yieldRange: [1, 20], aquiferType: 'Intergranular/confined', successRate: 0.75, notes: 'Reliable, moderate yield, often confined at depth' },
  { name: 'Limestone / Karst', depthRange: [20, 400], yieldRange: [0.5, 100], aquiferType: 'Karst/conduit', successRate: 0.70, notes: 'Extremely variable — cavities give high yield, or nothing' },
  { name: 'Coastal Sedimentary', depthRange: [10, 150], yieldRange: [2, 25], aquiferType: 'Multi-layered', successRate: 0.80, notes: 'Saltwater intrusion risk. Screen placement critical.' },
  { name: 'Dolomite / Marble', depthRange: [20, 200], yieldRange: [1, 50], aquiferType: 'Karst', successRate: 0.65, notes: 'Target dissolved cavities. Ground subsidence risk in South Africa.' },
];

/**
 * Look up regional borehole statistics for any country.
 */
export function getRegionalBoreholeStats(
  countryCode: string,
  country: string,
  region?: string,
): RegionalBoreholeStats {
  const code = countryCode?.toUpperCase();
  const known = COUNTRY_BOREHOLE_DATA[code];

  if (known) {
    return { ...known, region };
  }

  return {
    country: country || 'Unknown',
    countryCode: code || '??',
    region,
    ...DEFAULT_STATS,
  };
}

/**
 * Forward geocode a location description to get coordinates.
 * Used when client provides Country + Region + City + Village.
 */
export async function geocodeLocationForm(
  fields: {
    country?: string; region?: string; city?: string; county?: string; village?: string;
    province?: string; district?: string; location?: string; sublocation?: string;
    town?: string; estate?: string; farm?: string;
  },
): Promise<{
  latitude: number; longitude: number; displayName: string;
  country?: string; countryCode?: string; state?: string; county?: string;
  city?: string; village?: string;
} | null> {
  // Build query from most specific to least specific
  // Order: farm → estate → village → sublocation → location → town → district → county → city → province → region → country
  const parts = [
    fields.farm, fields.estate, fields.village, fields.sublocation,
    fields.location, fields.town, fields.district, fields.county,
    fields.city, fields.province, fields.region, fields.country,
  ].filter(Boolean);
  if (parts.length === 0) return null;

  // Try progressively less specific queries — drop the most-specific field each time
  const queries: string[] = [];
  for (let i = 0; i < Math.min(parts.length, 5); i++) {
    const q = parts.slice(i).join(', ');
    if (q.length > 2 && !queries.includes(q)) queries.push(q);
  }

  for (const q of queries) {
    try {
      const encoded = encodeURIComponent(q);
      const url = `https://nominatim.openstreetmap.org/search?format=json&q=${encoded}&limit=5&addressdetails=1&accept-language=en`;
      const res = await fetch(url, {
        headers: { 'User-Agent': 'EIMS-AquaScanPro/3.0 (borehole-analysis)' },
        signal: AbortSignal.timeout(10000),
      });
      if (!res.ok) continue;
      const results = await res.json();

      if (results.length > 0) {
        // Pick the best result — validate against user-supplied fields
        let best = results[0];
        if (results.length > 1 && (fields.county || fields.district || fields.region || fields.country)) {
          const lower = (s?: string) => (s || '').toLowerCase().trim();
          for (const candidate of results) {
            const addr = candidate.address || {};
            const countyMatch = !fields.county || [addr.county, addr.state_district, addr.district]
              .some((v: string) => lower(v).includes(lower(fields.county)));
            const districtMatch = !fields.district || [addr.state_district, addr.district, addr.county]
              .some((v: string) => lower(v).includes(lower(fields.district)));
            const regionMatch = !fields.region || [addr.state, addr.province, addr.region]
              .some((v: string) => lower(v).includes(lower(fields.region)));
            const provinceMatch = !fields.province || [addr.state, addr.province, addr.region]
              .some((v: string) => lower(v).includes(lower(fields.province)));
            const countryMatch = !fields.country || lower(addr.country).includes(lower(fields.country));
            if (countyMatch && districtMatch && regionMatch && provinceMatch && countryMatch) {
              best = candidate;
              break;
            }
          }
        }
        const r = best;
        const addr = r.address || {};
        console.log(`[LocationForm] "${q}" → ${r.display_name}`);
        return {
          latitude: parseFloat(r.lat),
          longitude: parseFloat(r.lon),
          displayName: r.display_name,
          country: addr.country,
          countryCode: addr.country_code?.toUpperCase(),
          state: addr.state || addr.province || addr.region,
          county: addr.county || addr.state_district || addr.district,
          city: addr.city || addr.town || addr.municipality,
          village: addr.village || addr.hamlet || addr.locality,
        };
      }
    } catch (err) {
      console.log(`[LocationForm] Error for "${q}":`, err);
    }
    // Rate limit — Nominatim requires 1s between requests
    await new Promise(r => setTimeout(r, 1100));
  }
  return null;
}
